class LogWriter:
    """Handles writing log messages to file with rotation support."""
    
    LOG_FORMAT = "[{timestamp}] [{level}] [{service}] [{request_id}] {message}\n"
    VALID_LEVELS = {"DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"}
    
    def __init__(self, config: LogConfig):
        self.config = config
        self._lock = threading.Lock()
        self._ensure_log_directory()
        self._log_path = os.path.join(config.log_dir, config.log_file)
    
    def _ensure_log_directory(self):
        os.makedirs(self.config.log_dir, exist_ok=True)
    
    def _get_file_size(self):
        try:
            return os.path.getsize(self._log_path)
        except OSError:
            return 0
    
    def _rotate_log(self):
        if not self.config.log_rotation:
            return
        if self._get_file_size() < self.config.max_file_size_bytes:
            return
        
        # Rotate existing backup files
        for i in range(self.config.max_backup_files - 1, 0, -1):
            src = "{}.{}".format(self._log_path, i)
            dst = "{}.{}".format(self._log_path, i + 1)
            if os.path.exists(src):
                if i + 1 > self.config.max_backup_files:
                    os.remove(src)
                else:
                    os.rename(src, dst)
        
        # Rotate current log file
        if os.path.exists(self._log_path):
            backup_path = "{}.1".format(self._log_path)
            os.rename(self._log_path, backup_path)
    
    def _validate_level(self, level):
        level_upper = level.upper().strip()
        if level_upper not in self.VALID_LEVELS:
            return "INFO"
        return level_upper
    
    def _sanitize_message(self, message):
        """Sanitize log message to prevent log injection."""
        if not isinstance(message, str):
            message = str(message)
        # Remove newlines and carriage returns to prevent log injection
        message = message.replace("\n", "\\n").replace("\r", "\\r")
        return message
    
    def _sanitize_field(self, field):
        """Sanitize a field value to prevent log injection."""
        if not isinstance(field, str):
            field = str(field)
        field = field.replace("\n", "").replace("\r", "").replace("[", "(").replace("]", ")")
        return field[:256]  # Limit field length
    
    def write_log(self, level, service, message, request_id="N/A", extra=None):
        timestamp = datetime.datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S.%f")[:-3] + " UTC"
        level = self._validate_level(level)
        service = self._sanitize_field(service)
        request_id = self._sanitize_field(request_id)
        message = self._sanitize_message(message)
        
        log_line = self.LOG_FORMAT.format(
            timestamp=timestamp,
            level=level,
            service=service,
            request_id=request_id,
            message=message
        )
        
        # Append extra metadata if present
        if extra and isinstance(extra, dict):
            extra_parts = []
            for key, value in extra.items():
                sanitized_key = self._sanitize_field(str(key))
                sanitized_value = self._sanitize_field(str(value))
                extra_parts.append("{}={}".format(sanitized_key, sanitized_value))
            if extra_parts:
                extra_line = "  >> metadata: {}\n".format(", ".join(extra_parts))
                log_line = log_line.rstrip("\n") + extra_line
        
        with self._lock:
            self._rotate_log()
            with open(self._log_path, "a", encoding="utf-8") as f:
                f.write(log_line)
            
            if self.config.enable_console_output:
                print(log_line, end="")
        
        return log_line
    
    def write_batch(self, log_entries):
        """Write multiple log entries at once."""
        results = []
        lines = []
        
        for entry in log_entries:
            if not isinstance(entry, dict):
                continue
            
            level = entry.get("level", "INFO")
            service = entry.get("service", "unknown")
            message = entry.get("message", "")
            request_id = entry.get("request_id", "N/A")
            extra = entry.get("extra", None)
            
            timestamp = datetime.datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S.%f")[:-3] + " UTC"
            level = self._validate_level(level)
            service = self._sanitize_field(service)
            request_id = self._sanitize_field(request_id)
            message = self._sanitize_message(message)
            
            log_line = self.LOG_FORMAT.format(
                timestamp=timestamp,
                level=level,
                service=service,
                request_id=request_id,
                message=message
            )
            
            if extra and isinstance(extra, dict):
                extra_parts = []
                for key, value in extra.items():
                    sanitized_key = self._sanitize_field(str(key))
                    sanitized_value = self._sanitize_field(str(value))
                    extra_parts.append("{}={}".format(sanitized_key, sanitized_value))
                if extra_parts:
                    extra_line = "  >> metadata: {}\n".format(", ".join(extra_parts))
                    log_line = log_line.rstrip("\n") + extra_line
            
            lines.append(log_line)
            results.append(log_line)
        
        with self._lock:
            self._rotate_log()
            with open(self._log_path, "a", encoding="utf-8") as f:
                f.writelines(lines)
            
            if self.config.enable_console_output:
                for line in lines:
                    print(line, end="")
        
        return results
    
    def query_logs(self, service=None, level=None, limit=100):
        """Query recent log entries with optional filters."""
        results = []
        try:
            with self._lock:
                with open(self._log_path, "r", encoding="utf-8") as f:
                    all_lines = f.readlines()
        except FileNotFoundError:
            return results
        
        for line in reversed(all_lines):
            if len(results) >= limit:
                break
            line = line.strip()
            if not line or line.startswith("  >>"):
                continue
            
            if service and "[{}]".format(service) not in line:
                continue
            if level and "[{}]".format(level.upper()) not in line:
                continue
            
            results.append(line)
        
        return results
    
    def get_stats(self):
        """Return log file statistics."""
        file_size = self._get_file_size()
        line_count = 0
        level_counts = {level: 0 for level in self.VALID_LEVELS}
        services = set()
        
        try:
            with self._lock:
                with open(self._log_path, "r", encoding="utf-8") as f:
                    for line in f:
                        if line.startswith("["):
                            line_count += 1
                            for lvl in self.VALID_LEVELS:
                                if "[{}]".format(lvl) in line:
                                    level_counts[lvl] += 1
                                    break
                            # Extract service name
                            parts = line.split("] [")
                            if len(parts) >= 3:
                                svc = parts[2].rstrip("]").strip()
                                if svc:
                                    services.add(svc)
        except FileNotFoundError:
            pass
        
        return {
            "file_path": self._log_path,
            "file_size_bytes": file_size,
            "file_size_mb": round(file_size / (1024 * 1024), 2),
            "total_entries": line_count,
            "level_counts": level_counts,
            "services": list(services),
            "max_file_size_mb": round(self.config.max_file_size_bytes / (1024 * 1024), 2),
            "rotation_enabled": self.config.log_rotation
        }


class LogRequestHandler(http.server.BaseHTTPRequestHandler):
    """HTTP request handler for the logging service."""
    
    log_writer = None  # Set by the server
    
    def _send_json_response(self, status_code, data):
        response_body = json.dumps(data, indent=2).encode("utf-8")
        self.send_response(status_code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(response_body)))
        self.end_headers()
        self.wfile.write(response_body)
    
    def _read_body(self):
        content_length = int(self.headers.get("Content-Length", 0))
        if content_length == 0:
            return None
        body = self.rfile.read(content_length)
        return json.loads(body.decode("utf-8"))
    
    def do_GET(self):
        parsed = urllib.parse.urlparse(self.path)
        path = parsed.path.rstrip("/")
        query_params = urllib.parse.parse_qs(parsed.query)
        
        if path == "" or path == "/":
            self._send_json_response(HTTPStatus.OK, {
                "service": "Centralized Logging Utility",
                "version": "1.0.0",
                "endpoints": {
                    "POST /log": "Submit a single log entry",
                    "POST /logs/batch": "Submit multiple log entries",
                    "GET /logs/query": "Query logs (params: service, level, limit)",
                    "GET /logs/stats": "Get log file statistics",
                    "GET /health": "Health check"
                }
            })
        elif path == "/health":
            self._send_json_response(HTTPStatus.OK, {
                "status": "healthy",
                "timestamp": datetime.datetime.utcnow().isoformat() + "Z"
            })
        elif path == "/logs/query":
            service = query_params.get("service", [None])[0]
            level = query_params.get("level", [None])[0]
            limit = int(query_params.get("limit", [100])[0])
            limit = min(limit, 10000)  # Cap at 10000
            
            results = self.log_writer.query_logs(
                service=service,
                level=level,
                limit=limit
            )
            self._send_json_response(HTTPStatus.OK, {
                "count": len(results),
                "filters": {
                    "service": service,
                    "level": level,
                    "limit": limit
                },
                "entries": results
            })
        elif path == "/logs/stats":
            stats = self.log_writer.get_stats()
            self._send_json_response(HTTPStatus.OK, stats)
        else:
            self._send_json_response(HTTPStatus.NOT_FOUND, {
                "error": "Not Found",
                "message": "Endpoint '{}' does not exist".format(self.path)
            })
    
    def do_POST(self):
        parsed = urllib.parse.urlparse(self.path)
        path = parsed.path.rstrip("/")
        
        try:
            body = self._read_body()
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "Invalid JSON body: {}".format(str(e))
            })
            return
        
        if body is None:
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "Request body is required"
            })
            return
        
        if path == "/log":
            self._handle_single_log(body)
        elif path == "/logs/batch":
            self._handle_batch_log(body)
        else:
            self._send_json_response(HTTPStatus.NOT_FOUND, {
                "error": "Not Found",
                "message": "Endpoint '{}' does not exist".format(self.path)
            })
    
    def _handle_single_log(self, body):
        # Validate required fields
        if not isinstance(body, dict):
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "Body must be a JSON object"
            })
            return
        
        message = body.get("message")
        if not message:
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "'message' field is required"
            })
            return
        
        service = body.get("service", "unknown")
        level = body.get("level", "INFO")
        request_id = body.get("request_id", "N/A")
        extra = body.get("extra", None)
        
        log_line = self.log_writer.write_log(
            level=level,
            service=service,
            message=message,
            request_id=request_id,
            extra=extra
        )
        
        self._send_json_response(HTTPStatus.CREATED, {
            "status": "logged",
            "entry": log_line.strip()
        })
    
    def _handle_batch_log(self, body):
        if not isinstance(body, dict):
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "Body must be a JSON object with 'entries' array"
            })
            return
        
        entries = body.get("entries")
        if not entries or not isinstance(entries, list):
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "'entries' field must be a non-empty array"
            })
            return
        
        if len(entries) > 1000:
            self._send_json_response(HTTPStatus.BAD_REQUEST, {
                "error": "Bad Request",
                "message": "Maximum 1000 entries per batch"
            })
            return
        
        # Validate each entry has a message
        for i, entry in enumerate(entries):
            if not isinstance(entry, dict) or not entry.get("message"):
                self._send_json_response(HTTPStatus.BAD_REQUEST, {
                    "error": "Bad Request",
                    "message": "Entry at index {} is invalid or missing 'message'".format(i)
                })
                return
        
        results = self.log_writer.write_batch(entries)
        
        self._send_json_response(HTTPStatus.CREATED, {
            "status": "logged",
            "count": len(results),
            "entries": [r.strip() for r in results]
        })
    
    def log_message(self, format, *args):
        """Override to log access to our own log file."""
        message = "HTTP {} {} {}".format(
            self.client_address[0],
            self.command if hasattr(self, 'command') else 'UNKNOWN',
            format % args
        )
        self.log_writer.write_log(
            level="DEBUG",
            service="log-server",
            message=message,
            request_id="internal"
        )


class LogServer:
    """Centralized logging HTTP server."""
    
    def __init__(self, config=None):
        if config is None:
            config = LogConfig()
        self.config = config
        self.log_writer = LogWriter(config)
        self._server = None
    
    def start(self):
        """Start the logging server."""
        handler_class = LogRequestHandler
        handler_class.log_writer = self.log_writer
        
        self._server = http.server.ThreadingHTTPServer(
            (self.config.host, self.config.port),
            handler_class
        )
        
        startup_msg = "Centralized Logging Server started on {}:{}".format(
            self.config.host, self.config.port
        )
        self.log_writer.write_log(
            level="INFO",
            service="log-server",
            message=startup_msg,
            request_id="startup"
        )
        
        print("=" * 60)
        print("  Centralized Logging Utility")
        print("  Listening on {}:{}".format(self.config.host, self.config.port))
        print("  Log file: {}".format(
            os.path.join(self.config.log_dir, self.config.log_file)
        ))
        print("=" * 60)
        print()
        print("Endpoints:")
        print("  POST /log          - Submit a log entry")
        print("  POST /logs/batch   - Submit multiple log entries")
        print("  GET  /logs/query   - Query logs")
        print("  GET  /logs/stats   - Log statistics")
        print("  GET  /health       - Health check")
        print()
        
        try:
            self._server.serve_forever()
        except KeyboardInterrupt:
            self.stop()
    
    def stop(self):
        """Stop the logging server."""
        if self._server:
            shutdown_msg = "Centralized Logging Server shutting down"
            self.log_writer.write_log(
                level="INFO",
                service="log-server",
                message=shutdown_msg,
                request_id="shutdown"
            )
            self._server.shutdown()
            self._server.server_close()
            print("\nServer stopped.")


